args.sparql:
SELECT ?novel ?novelLabel ?character ?characterLabel
WHERE {
  VALUES ?novel { wd:Q36097 wd:Q682733 }
  ?novel wdt:P674 ?character.
  ?character rdfs:label ?characterLabel.
  ?novel rdfs:label ?novelLabel.
  FILTER(LANG(?novelLabel) = 'en')
  FILTER(LANG(?characterLabel) = 'en')
}

SELECT ?novel ?novelLabel ?character ?characterLabel
WHERE {
  VALUES ?novel { wd:Q36097 wd:Q682733 }
  ?novel wdt:P674 ?character.
  ?character wdt:P21 wd:Q6581097.
  ?novel rdfs:label ?novelLabel.
  ?character rdfs:label ?characterLabel.
}
